// QR renderer placeholder.
//
// The reference client uses a QRCode global. Drop in any QR library that
// exposes `new QRCode(element, options)`:
//
//   * https://github.com/papnkukn/qrcode-svg (MIT) — vendored as a single
//     minified file works well
//   * https://github.com/davidshimjs/qrcodejs (MIT) — popular vanilla-JS
//     QR lib with the exact same API
//
// We don't ship a real bundle in-repo because we don't want to be the
// canonical source of a third-party JS dep. Save the minified file from
// the lib of your choice as this file, or just inline a CDN <script> tag
// in index.html. The lib only needs ~5 KB.
window.QRCode = class {
  constructor(el, opts) {
    el.innerText =
      "QR placeholder — vendor a real qrcode lib (e.g. qrcode-svg) " +
      "into docs/dash-is-login/reference-client/vendor/qrcode.min.js. " +
      "URI: " + (opts && opts.content);
  }
};
